IF COL_LENGTH(N'dbo.INSTRUCCION', N'MODELO') IS NULL
BEGIN
	ALTER TABLE dbo.INSTRUCCION
		ADD [MODELO] NVARCHAR(40) NOT NULL
		CONSTRAINT [DF_INSTRUCCION_MODELO] DEFAULT (N'gpt-5-nano');
END;

SET NOCOUNT ON;
SET XACT_ABORT ON;
BEGIN TRAN;
UPDATE dbo.INSTRUCCION SET [MODELO] = N'gpt-5-nano';
COMMIT;

